124: 	}
125: 	if r.IgnoreValue && len(r.Value) != 0 {
126: 		return rpctypes.ErrGRPCValueProvided
127: 	}
128: 	if r.IgnoreLease && r.Lease != 0 {
129: 		return rpctypes.ErrGRPCLeaseProvided
