350: func (s *EtcdServer) checkLeaseTimeToLive(ctx context.Context, leaseID lease.LeaseID) (uint64, error) {
351: 	rev := s.AuthStore().Revision()
352: 	if !s.AuthStore().IsAuthEnabled() {
353: 		return rev, nil
354: 	}
355: 	authInfo, err := s.AuthInfoFromCtx(ctx)
356: 	if err != nil {
357: 		return rev, err
358: 	}
359: 	if authInfo == nil {
360: 		return rev, auth.ErrUserEmpty
361: 	}
362: 
363: 	l := s.lessor.Lookup(leaseID)
364: 	if l != nil {
365: 		for _, key := range l.Keys() {
366: 			if err := s.AuthStore().IsRangePermitted(authInfo, []byte(key), []byte{}); err != nil {
367: 				return 0, err
368: 			}
369: 		}
370: 	}
371: 
372: 	return rev, nil
373: }
374: 
375: func (s *EtcdServer) leaseTimeToLive(ctx context.Context, r *pb.LeaseTimeToLiveRequest) (*pb.LeaseTimeToLiveResponse, error) {
376: 	if s.isLeader() {
377: 		if err := s.waitAppliedIndex(); err != nil {
378: 			return nil, err
379: 		}
380: 
381: 		// gofail: var beforeLookupWhenLeaseTimeToLive struct{}
382: 
383: 		// primary; timetolive directly from leader
384: 		le := s.lessor.Lookup(lease.LeaseID(r.ID))
385: 		if le == nil {
386: 			return nil, lease.ErrLeaseNotFound
387: 		}
388: 		// TODO: fill out ResponseHeader
389: 		resp := &pb.LeaseTimeToLiveResponse{Header: &pb.ResponseHeader{}, ID: r.ID, TTL: int64(le.Remaining().Seconds()), GrantedTTL: le.TTL()}
390: 		if r.Keys {
391: 			ks := le.Keys()
392: 			kbs := make([][]byte, len(ks))
393: 			for i := range ks {
394: 				kbs[i] = []byte(ks[i])
395: 			}
396: 			resp.Keys = kbs
397: 		}
398: 
399: 		// The leasor could be demoted if leader changed during lookup.
400: 		// We should return error to force retry instead of returning
401: 		// incorrect remaining TTL.
402: 		if le.Demoted() {
403: 			// NOTE: lease.ErrNotPrimary is not retryable error for
404: 			// client. Instead, uses ErrLeaderChanged.
405: 			return nil, ErrLeaderChanged
406: 		}
407: 		return resp, nil
408: 	}
409: 
410: 	cctx, cancel := context.WithTimeout(ctx, s.Cfg.ReqTimeout())
411: 	defer cancel()
412: 
413: 	// forward to leader
414: 	for cctx.Err() == nil {
415: 		leader, err := s.waitLeader(cctx)
416: 		if err != nil {
417: 			return nil, err
418: 		}
419: 		for _, url := range leader.PeerURLs {
420: 			lurl := url + leasehttp.LeaseInternalPrefix
421: 			resp, err := leasehttp.TimeToLiveHTTP(cctx, lease.LeaseID(r.ID), r.Keys, lurl, s.peerRt)
422: 			if err == nil {
423: 				return resp.LeaseTimeToLiveResponse, nil
424: 			}
425: 			if err == lease.ErrLeaseNotFound {
426: 				return nil, err
427: 			}
428: 		}
429: 	}
430: 
431: 	if cctx.Err() == context.DeadlineExceeded {
432: 		return nil, ErrTimeout
433: 	}
434: 	return nil, ErrCanceled
435: }
436: 
437: func (s *EtcdServer) LeaseTimeToLive(ctx context.Context, r *pb.LeaseTimeToLiveRequest) (*pb.LeaseTimeToLiveResponse, error) {
438: 	var rev uint64
439: 	var err error
440: 	if r.Keys {
441: 		// check RBAC permission only if Keys is true
442: 		rev, err = s.checkLeaseTimeToLive(ctx, lease.LeaseID(r.ID))
443: 		if err != nil {
444: 			return nil, err
445: 		}
446: 	}
447: 
448: 	resp, err := s.leaseTimeToLive(ctx, r)
449: 	if err != nil {
450: 		return nil, err
451: 	}
452: 
453: 	if r.Keys {
454: 		if s.AuthStore().IsAuthEnabled() && rev != s.AuthStore().Revision() {
455: 			return nil, auth.ErrAuthOldRevision
456: 		}
457: 	}
458: 	return resp, nil
459: }
