471: func (s *EtcdServer) waitLeader(ctx context.Context) (*membership.Member, error) {
472: 	leader := s.cluster.Member(s.Leader())
473: 	for leader == nil {
474: 		// wait an election
475: 		dur := time.Duration(s.Cfg.ElectionTicks) * time.Duration(s.Cfg.TickMs) * time.Millisecond
476: 		select {
477: 		case <-time.After(dur):
478: 			leader = s.cluster.Member(s.Leader())
479: 		case <-s.stopping:
480: 			return nil, ErrStopped
481: 		case <-ctx.Done():
482: 			return nil, ErrNoLeader
483: 		}
484: 	}
485: 	if leader == nil || len(leader.PeerURLs) == 0 {
486: 		return nil, ErrNoLeader
487: 	}
488: 	return leader, nil
489: }
