523: func (s *EtcdServer) Authenticate(ctx context.Context, r *pb.AuthenticateRequest) (*pb.AuthenticateResponse, error) {
524: 	if err := s.linearizableReadNotify(ctx); err != nil {
525: 		return nil, err
526: 	}
527: 
528: 	lg := s.Logger()
529: 
530: 	// fix https://nvd.nist.gov/vuln/detail/CVE-2021-28235
531: 	defer func() {
532: 		if r != nil {
533: 			r.Password = ""
534: 		}
535: 	}()
536: 
537: 	var resp proto.Message
538: 	for {
539: 		checkedRevision, err := s.AuthStore().CheckPassword(r.Name, r.Password)
540: 		if err != nil {
541: 			if err != auth.ErrAuthNotEnabled {
542: 				lg.Warn(
543: 					"invalid authentication was requested",
544: 					zap.String("user", r.Name),
545: 					zap.Error(err),
546: 				)
547: 			}
548: 			return nil, err
549: 		}
550: 
551: 		st, err := s.AuthStore().GenTokenPrefix()
552: 		if err != nil {
553: 			return nil, err
554: 		}
555: 
556: 		// internalReq doesn't need to have Password because the above s.AuthStore().CheckPassword() already did it.
557: 		// In addition, it will let a WAL entry not record password as a plain text.
558: 		internalReq := &pb.InternalAuthenticateRequest{
559: 			Name:        r.Name,
560: 			SimpleToken: st,
561: 		}
562: 
563: 		resp, err = s.raftRequestOnce(ctx, pb.InternalRaftRequest{Authenticate: internalReq})
564: 		if err != nil {
565: 			return nil, err
566: 		}
567: 		if checkedRevision == s.AuthStore().Revision() {
568: 			break
569: 		}
570: 
571: 		lg.Info("revision when password checked became stale; retrying")
572: 	}
573: 
574: 	return resp.(*pb.AuthenticateResponse), nil
575: }
