748: func (s *EtcdServer) processInternalRaftRequestOnce(ctx context.Context, r pb.InternalRaftRequest) (*applyResult, error) {
749: 	ai := s.getAppliedIndex()
750: 	ci := s.getCommittedIndex()
751: 	if ci > ai+maxGapBetweenApplyAndCommitIndex {
752: 		return nil, ErrTooManyRequests
753: 	}
754: 
755: 	r.Header = &pb.RequestHeader{
756: 		ID: s.reqIDGen.Next(),
757: 	}
758: 
759: 	// check authinfo if it is not InternalAuthenticateRequest
760: 	if r.Authenticate == nil {
761: 		authInfo, err := s.AuthInfoFromCtx(ctx)
762: 		if err != nil {
763: 			return nil, err
764: 		}
765: 		if authInfo != nil {
766: 			r.Header.Username = authInfo.Username
767: 			r.Header.AuthRevision = authInfo.Revision
768: 		}
769: 	}
770: 
771: 	data, err := r.Marshal()
772: 	if err != nil {
773: 		return nil, err
774: 	}
775: 
776: 	if len(data) > int(s.Cfg.MaxRequestBytes) {
777: 		return nil, ErrRequestTooLarge
778: 	}
779: 
780: 	id := r.ID
781: 	if id == 0 {
782: 		id = r.Header.ID
783: 	}
784: 	ch := s.w.Register(id)
785: 
786: 	cctx, cancel := context.WithTimeout(ctx, s.Cfg.ReqTimeout())
787: 	defer cancel()
788: 
789: 	start := time.Now()
790: 	err = s.r.Propose(cctx, data)
791: 	if err != nil {
792: 		proposalsFailed.Inc()
793: 		s.w.Trigger(id, nil) // GC wait
794: 		return nil, err
795: 	}
796: 	proposalsPending.Inc()
797: 	defer proposalsPending.Dec()
798: 
799: 	select {
800: 	case x := <-ch:
801: 		return x.(*applyResult), nil
802: 	case <-cctx.Done():
803: 		proposalsFailed.Inc()
804: 		s.w.Trigger(id, nil) // GC wait
805: 		return nil, s.parseProposeCtxErr(cctx.Err(), start)
806: 	case <-s.done:
807: 		return nil, ErrStopped
808: 	}
809: }
