814: func (s *EtcdServer) linearizableReadLoop() {
815: 	for {
816: 		requestId := s.reqIDGen.Next()
817: 		leaderChangedNotifier := s.LeaderChangedNotify()
818: 		select {
819: 		case <-leaderChangedNotifier:
820: 			continue
821: 		case <-s.readwaitc:
822: 		case <-s.stopping:
823: 			return
824: 		}
825: 
826: 		// as a single loop is can unlock multiple reads, it is not very useful
827: 		// to propagate the trace from Txn or Range.
828: 		trace := traceutil.New("linearizableReadLoop", s.Logger())
829: 
830: 		nextnr := newNotifier()
831: 		s.readMu.Lock()
832: 		nr := s.readNotifier
833: 		s.readNotifier = nextnr
834: 		s.readMu.Unlock()
835: 
836: 		confirmedIndex, err := s.requestCurrentIndex(leaderChangedNotifier, requestId)
837: 		if isStopped(err) {
838: 			return
839: 		}
840: 		if err != nil {
841: 			nr.notify(err)
842: 			continue
843: 		}
844: 
845: 		trace.Step("read index received")
846: 
847: 		trace.AddField(traceutil.Field{Key: "readStateIndex", Value: confirmedIndex})
848: 
849: 		appliedIndex := s.getAppliedIndex()
850: 		trace.AddField(traceutil.Field{Key: "appliedIndex", Value: strconv.FormatUint(appliedIndex, 10)})
851: 
852: 		if appliedIndex < confirmedIndex {
853: 			select {
854: 			case <-s.applyWait.Wait(confirmedIndex):
855: 			case <-s.stopping:
856: 				return
857: 			}
858: 		}
859: 		// unblock all l-reads requested at indices before confirmedIndex
860: 		nr.notify(nil)
861: 		trace.Step("applied index is now lower than readState.Index")
862: 
863: 		trace.LogAllStepsIfLong(traceThreshold)
864: 	}
865: }
