871: func (s *EtcdServer) requestCurrentIndex(leaderChangedNotifier <-chan struct{}, requestId uint64) (uint64, error) {
872: 	err := s.sendReadIndex(requestId)
873: 	if err != nil {
874: 		return 0, err
875: 	}
876: 
877: 	lg := s.Logger()
878: 	errorTimer := time.NewTimer(s.Cfg.ReqTimeout())
879: 	defer errorTimer.Stop()
880: 	retryTimer := time.NewTimer(readIndexRetryTime)
881: 	defer retryTimer.Stop()
882: 
883: 	firstCommitInTermNotifier := s.FirstCommitInTermNotify()
884: 
885: 	for {
886: 		select {
887: 		case rs := <-s.r.readStateC:
888: 			requestIdBytes := uint64ToBigEndianBytes(requestId)
889: 			gotOwnResponse := bytes.Equal(rs.RequestCtx, requestIdBytes)
890: 			if !gotOwnResponse {
891: 				// a previous request might time out. now we should ignore the response of it and
892: 				// continue waiting for the response of the current requests.
893: 				responseId := uint64(0)
894: 				if len(rs.RequestCtx) == 8 {
895: 					responseId = binary.BigEndian.Uint64(rs.RequestCtx)
896: 				}
897: 				lg.Warn(
898: 					"ignored out-of-date read index response; local node read indexes queueing up and waiting to be in sync with leader",
899: 					zap.Uint64("sent-request-id", requestId),
900: 					zap.Uint64("received-request-id", responseId),
901: 				)
902: 				slowReadIndex.Inc()
903: 				continue
904: 			}
905: 			return rs.Index, nil
906: 		case <-leaderChangedNotifier:
907: 			readIndexFailed.Inc()
908: 			// return a retryable error.
909: 			return 0, ErrLeaderChanged
910: 		case <-firstCommitInTermNotifier:
911: 			firstCommitInTermNotifier = s.FirstCommitInTermNotify()
912: 			lg.Info("first commit in current term: resending ReadIndex request")
913: 			err := s.sendReadIndex(requestId)
914: 			if err != nil {
915: 				return 0, err
916: 			}
917: 			retryTimer.Reset(readIndexRetryTime)
918: 			continue
919: 		case <-retryTimer.C:
920: 			lg.Warn(
921: 				"waiting for ReadIndex response took too long, retrying",
922: 				zap.Uint64("sent-request-id", requestId),
923: 				zap.Duration("retry-timeout", readIndexRetryTime),
924: 			)
925: 			err := s.sendReadIndex(requestId)
926: 			if err != nil {
927: 				return 0, err
928: 			}
929: 			retryTimer.Reset(readIndexRetryTime)
930: 			continue
931: 		case <-errorTimer.C:
932: 			lg.Warn(
933: 				"timed out waiting for read index response (local node might have slow network)",
934: 				zap.Duration("timeout", s.Cfg.ReqTimeout()),
935: 			)
936: 			slowReadIndex.Inc()
937: 			return 0, ErrTimeout
938: 		case <-s.stopping:
939: 			return 0, ErrStopped
940: 		}
941: 	}
942: }
